package sesiunea3;

import java.util.Scanner;

public class TestSwitch {
	
	static final Scanner input = new Scanner ( System . in ) ;


	public static void main(String[] args) {
		// TODO Auto-generated method stub

	
		
		int x = 10;
		// ...
		switch ( x ) {
			case 0:
				System . out .print (" A ") ;
				break ;
			case 1:
				System . out .print (" B ") ;
			case 2:
				System . out .print (" C ") ;
				break ;
			default :
				System . out .print (" D ") ;
				break ;
		}
		
		
		
		
	}

}
